from functools import wraps

def require_role(*allowed_roles):
    """Decorator that enforces role check using verified auth context."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            # Auth context injected by middleware from verified JWT - never from conversation
            auth_ctx = get_current_auth_context()
            if auth_ctx["role"] not in allowed_roles:
                raise AuthorizationError(
                    f"Role '{auth_ctx['role']}' cannot execute '{func.__name__}'. "
                    f"Required: {allowed_roles}"
                )
            # Force tenant scoping from auth context
            if "tenant_id" in kwargs:
                if kwargs["tenant_id"] != auth_ctx["tenant_id"] and auth_ctx["role"] != "platform_admin":
                    raise AuthorizationError("Cross-tenant access denied")
            return func(*args, **kwargs)
        return wrapper
    return decorator

