from langchain_core.tools import tool
from RestrictedPython import compile_restricted, safe_globals
from RestrictedPython.Eval import default_guarded_getiter, default_guarded_getattr
import resource
import signal

ALLOWED_MODULES = {'math', 'statistics', 'datetime', 'json', 'collections'}
ALLOWED_BUILTINS = {
    'len', 'range', 'enumerate', 'zip', 'map', 'filter', 'sorted',
    'sum', 'min', 'max', 'abs', 'round', 'int', 'float', 'str',
    'list', 'dict', 'set', 'tuple', 'bool', 'print', 'isinstance'
}

def create_restricted_globals():
    """Create a restricted execution environment."""
    restricted = safe_globals.copy()
    restricted['_getiter_'] = default_guarded_getiter
    restricted['_getattr_'] = default_guarded_getattr

    # Only allow safe builtins
    safe_builtins = {k: __builtins__[k] if isinstance(__builtins__, dict) else getattr(__builtins__, k)
                     for k in ALLOWED_BUILTINS}

    def restricted_import(name, *args, **kwargs):
        if name not in ALLOWED_MODULES:
            raise ImportError(f"Module '{name}' is not allowed. Permitted: {ALLOWED_MODULES}")
        return __import__(name, *args, **kwargs)

    safe_builtins['__import__'] = restricted_import
    restricted['__builtins__'] = safe_builtins
    return restricted

def execute_sandboxed(code: str, timeout_seconds: int = 5) -> dict:
    """Execute code in restricted sandbox with resource limits."""
    # Compile with RestrictedPython
    compiled = compile_restricted(code, '<analysis>', 'exec')
    if compiled.errors:
        raise ValueError(f"Code compilation errors: {compiled.errors}")

    restricted_globals = create_restricted_globals()
    local_vars = {}

    # Set resource limits
    def timeout_handler(signum, frame):
        raise TimeoutError("Code execution timed out")

    old_handler = signal.signal(signal.SIGALRM, timeout_handler)
    signal.alarm(timeout_seconds)

    try:
        exec(compiled.code, restricted_globals, local_vars)
    finally:
        signal.alarm(0)
        signal.signal(signal.SIGALRM, old_handler)

    return {"result": local_vars.get("result", "Analysis complete")}

@tool
def run_analysis(analysis_description: str) -> dict:
    """Generate and run a sandboxed Python analysis script."""
    code = llm.invoke(
        f"Write a Python script using only these modules: {ALLOWED_MODULES}.\n"
        f"Task: {analysis_description}\n"
        f"Store the final result in a variable named 'result'."
    ).content
    code = code.strip('`').removeprefix('python\n')
    return execute_sandboxed(code)

