from langchain_core.tools import tool
from datetime import datetime, timedelta
import hashlib

# Workflow-level constraints enforced server-side

class WorkflowGuard:
    """Tracks tool call sequences and enforces workflow-level policies."""

    FORBIDDEN_CHAINS = [
        # Cannot upload evidence and evaluate the same control in one session
        ("upload_evidence", "evaluate_control"),
        # Cannot bulk query then bulk modify
        ("query_audit_log", "evaluate_control"),
    ]

    def __init__(self):
        self.call_history: list[dict] = []

    def check_chain(self, tool_name: str, args: dict) -> bool:
        for prev_tool, blocked_tool in self.FORBIDDEN_CHAINS:
            if tool_name == blocked_tool:
                recent_calls = [c for c in self.call_history[-10:] if c["tool"] == prev_tool]
                if recent_calls:
                    # Check if the same control_id is involved
                    prev_control_ids = {c["args"].get("control_id") for c in recent_calls}
                    if args.get("control_id") in prev_control_ids or not args.get("control_id"):
                        return False
        return True

    def record_call(self, tool_name: str, args: dict):
        self.call_history.append({"tool": tool_name, "args": args, "time": datetime.utcnow()})

def workflow_guarded_tool_node(state: AgentState):
    """Tool execution with workflow-level chain validation."""
    guard = state.get("workflow_guard", WorkflowGuard())
    last_message = state["messages"][-1]

    for tc in last_message.tool_calls:
        if not guard.check_chain(tc["name"], tc["args"]):
            raise WorkflowViolation(
                f"Tool chain policy violation: '{tc['name']}' cannot follow recent tool calls. "
                f"This operation requires a separate session or approval workflow."
            )
        guard.record_call(tc["name"], tc["args"])

    result = tool_node.invoke(state)
    return {**result, "workflow_guard": guard}

@tool
@require_role("auditor", "admin")
def upload_evidence(control_id: str, content: str) -> dict:
    """Upload evidence for a control. Requires separate review before evaluation."""
    evidence_id = f"EVD-{uuid4()}"
    # Evidence is marked as 'pending_review' - cannot be used in evaluation until reviewed
    s3.put_object(
        Bucket=BUCKET,
        Key=f"{control_id}/{evidence_id}",
        Body=content,
        Metadata={"status": "pending_review", "uploaded_by": get_current_auth_context()["user_id"]}
    )
    return {"evidence_id": evidence_id, "status": "pending_review", "note": "Evidence must be reviewed before it can be used in evaluations"}

@tool
@require_role("auditor", "admin")
def evaluate_control(control_id: str, evidence_ids: list) -> dict:
    """Evaluate a control. Only reviewed evidence from other users is accepted."""
    auth = get_current_auth_context()
